python3 << 'PYEOF'
import json

# Validate final_result.json against its schema
with open('/workspace/work/final_result.json', 'r') as f:
    final = json.load(f)

with open('/workspace/runtime-schemas/final_result.schema.json', 'r') as f:
    schema = json.load(f)

# Check required fields
required = schema.get('required', [])
for field in required:
    if field not in final:
        print(f"MISSING required field: {field}")
    else:
        print(f"OK: {field} = {json.dumps(final[field], ensure_ascii=False)[:80]}")

# Check types
print(f"\nanomaly_ids type: {type(final['anomaly_ids']).__name__}, value: {final['anomaly_ids']}")
print(f"record_ids type: {type(final['record_ids']).__name__}, value: {final['record_ids']}")
print(f"answer type: {type(final['answer']).__name__}, len: {len(final['answer'])}")
print(f"citations type: {type(final['citations']).__name__}, value: {final['citations']}")

# Check pattern for record_ids
import re
for rid in final['record_ids']:
    if re.match(r'^R[0-9]{6}$', rid):
        print(f"record_id {rid}: OK")
    else:
        print(f"record_id {rid}: INVALID pattern")

# Validate evidence_matrix.json against its schema
with open('/workspace/work/evidence_matrix.json', 'r') as f:
    evidence = json.load(f)

with open('/workspace/runtime-schemas/evidence_matrix.schema.json', 'r') as f:
    ev_schema = json.load(f)

print("\n--- Evidence Matrix ---")
ev_required = ev_schema.get('required', [])
for field in ev_required:
    if field not in evidence:
        print(f"MISSING required field: {field}")
    else:
        val = evidence[field]
        if isinstance(val, list):
            print(f"OK: {field} = list[{len(val)}]")
        elif isinstance(val, dict):
            print(f"OK: {field} = dict{list(val.keys())}")
        else:
            print(f"OK: {field} = {val}")

print(f"\nevidence_rows count: {len(evidence['evidence_rows'])}")
for i, row in enumerate(evidence['evidence_rows']):
    row_req = ev_schema['properties']['evidence_rows']['items']['required']
    for field in row_req:
        if field not in row:
            print(f"  row[{i}] MISSING: {field}")
        else:
            val = row[field]
            if isinstance(val, list):
                print(f"  row[{i}].{field} = list[{len(val)}]")
            elif isinstance(val, dict):
                print(f"  row[{i}].{field} = dict")
            elif isinstance(val, bool):
                print(f"  row[{i}].{field} = {val}")
            else:
                s = str(val)[:60]
                print(f"  row[{i}].{field} = '{s}...'")
PYEOF
